/*! html5-qrcode (light build) - camera QR scanning */
(function(){function t(e){return new Promise(function(n,r){var o=document.createElement("script");o.src=e,o.async=!0,o.onload=function(){n()};o.onerror=function(){r(new Error("Failed to load "+e))};document.head.appendChild(o)})}async function e(){if(window.Html5Qrcode)return;await t("https://unpkg.com/html5-qrcode")}window.__loadHtml5Qrcode=e})();
// Waiter QR code scanner script
let scanner = null;

async function startScanner() {
  try {
    await window.__loadHtml5Qrcode();
  } catch (e) {
    console.error("Failed to load html5-qrcode:", e);
    return;
  }

  if (scanner) {
    await scanner.stop();
    scanner = null;
  }

  scanner = new Html5Qrcode("reader");

  try {
    await scanner.start(
      { facingMode: "environment" },
      { fps: 10, qrbox: { width: 260, height: 260 } },
      (decodedText) => {
        console.log("Scanned:", decodedText);
      },
      () => {}
    );
  } catch (e) {
    console.error("Failed to start scanner:", e);
  }
}

startScanner();
async function stopScanner() {
  try {
    if (scanner) {
      await scanner.stop();
      await scanner.clear();
      scanner = null;
    }
  } catch (e) {
    console.error(e);
  }
}